                        if self.payload != nil { try decoder.handleConflictingOneOf() }
                        self.payload = .sessionInfo(v)
                    }
                }()
            case 50: try decoder.decodeSingularBytesField(value: &requestUuid)
            case 51: try decoder.decodeSingularBytesField(value: &uuid)
            case 52: try decoder.decodeSingularUInt32Field(value: &flags)
            default: break
            }
        }
    }

    public func traverse(visitor: inout some SwiftProtobuf.Visitor) throws {
        // The use of inline closures is to circumvent an issue where the compiler
        // allocates stack space for every if/case branch local when no optimizations
        // are enabled. https://github.com/apple/swift-protobuf/issues/1034 and
        // https://github.com/apple/swift-protobuf/issues/1182
        if let v = _toDestination {
            try visitor.visitSingularMessageField(value: v, fieldNumber: 6)
        }
        try { if let v = self._fromDestination {
            try visitor.visitSingularMessageField(value: v, fieldNumber: 7)
        } }()
        try { if case let .protobufMessageAsBytes(v)? = self.payload {
            try visitor.visitSingularBytesField(value: v, fieldNumber: 10)
        } }()
        try { if let v = self._signedMessageStatus {
            try visitor.visitSingularMessageField(value: v, fieldNumber: 12)
        } }()
        try { if case let .signatureData(v)? = self.subSigData {
            try visitor.visitSingularMessageField(value: v, fieldNumber: 13)
        } }()
        switch payload {
        case .sessionInfoRequest?: try {
                guard case let .sessionInfoRequest(v)? = self.payload else { preconditionFailure() }
                try visitor.visitSingularMessageField(value: v, fieldNumber: 14)
            }()
        case .sessionInfo?: try {
                guard case let .sessionInfo(v)? = self.payload else { preconditionFailure() }
                try visitor.visitSingularBytesField(value: v, fieldNumber: 15)
            }()
        default: break
        }
        if !requestUuid.isEmpty {
            try visitor.visitSingularBytesField(value: requestUuid, fieldNumber: 50)
        }
        if !uuid.isEmpty {
            try visitor.visitSingularBytesField(value: uuid, fieldNumber: 51)
        }
        if flags != 0 {
            try visitor.visitSingularUInt32Field(value: flags, fieldNumber: 52)
        }
        try unknownFields.traverse(visitor: &visitor)
    }

    public static func == (lhs: UniversalMessage_RoutableMessage, rhs: UniversalMessage_RoutableMessage) -> Bool {
        if lhs._toDestination != rhs._toDestination { return false }
        if lhs._fromDestination != rhs._fromDestination { return false }
        if lhs.payload != rhs.payload { return false }
        if lhs.subSigData != rhs.subSigData { return false }
        if lhs._signedMessageStatus != rhs._signedMessageStatus { return false }
        if lhs.requestUuid != rhs.requestUuid { return false }
        if lhs.uuid != rhs.uuid { return false }
        if lhs.flags != rhs.flags { return false }
        if lhs.unknownFields != rhs.unknownFields { return false }
        return true
    }
}
